        if (candidates.length === 0) {
            return -1;
        }

        candidates.sort((a, b) => {
            if (frequency[b] !== frequency[a]) {
                return frequency[b] - frequency[a];
            } else {
                return a - b;
            }
        });

        return candidates[0];
    });
}
